/**
 * Get a table value for a specific archetype and level
 */
export function getTableValue(
  archetype: string,
  tableName: string,
  level: number
): number | undefined {
  const at = AT_TABLES[archetype];
  if (!at) return undefined;
  
  const key = tableName.toLowerCase();
  let table = at.tables[key];
  
  // Power data uses suffixed names (e.g., "Ranged_HealSelf") that map to
  // base table names (e.g., "ranged_heal"). Strip common suffixes to match.
  if (!table) {
    const stripped = key.replace(/self$|other$|target$/, '');
    table = at.tables[stripped];
  }
  
  // Alias temp/incarnate damage tables to base damage tables
  if (!table) {
    const aliased = key
      .replace('_tempdamage', '_damage')
      .replace('_incarnateprocdamage', '_damage');
    if (aliased !== key) table = at.tables[aliased];
  }
  
  if (!table) return undefined;
  
  // Level 1 = index 0; clamp to table length (HC has 105 values,
  // Rebirth has 50 — different versions cap at different levels).
  const index = Math.max(0, Math.min(table.length - 1, level - 1));
  return table[index];
}

/**
 * Calculate the final effect value from scale and table
 * Example: scale 2.5 with ranged_debuff_tohit at level 50 = 2.5 * -0.125 = -31.25%
 */
export function calculateEffectValue(
  archetype: string,
  tableName: string,
  scale: number,
  level: number = 50
): number | undefined {
  const tableValue = getTableValue(archetype, tableName, level);
  if (tableValue === undefined) return undefined;
  return scale * tableValue;
}

/**
 * Calculate incarnate power damage from scale and table
 */
export function calculateIncarnateDamage(
  scale: number,
  tableName: string,
  archetype: string,
  level: number = 50
): number | null {
  if (!scale || scale === 0) return 0;
  const tableValue = getTableValue(archetype, tableName.toLowerCase().replace(/-/g, '_'), level);
  if (tableValue === undefined) return null;
  return Math.abs(scale * tableValue);
}

